SELECT id, customer_id as "userId", session_id as "sessionId", subtotal, currency, coupon_codes as "couponCodes", discount_amount as "discountAmount", total, expires_at as "expiresAt", notes, description, state_id as "stateId", flow_id as "flowId", created_time as "createdTime", last_modified_time as "lastModifiedTime", last_modified_by as "lastModifiedBy", created_by as "createdBy", tenant, version FROM cart
customer_id = #{userId}
AND state_id = #{stateId}
${orderby} ${pagination}

SELECT id, customer_id as "userId", subtotal, currency, discount_amount as "discountAmount", total, state_id as "stateId", flow_id as "flowId", created_time as "createdTime", last_modified_time as "lastModifiedTime" FROM cart WHERE state_id = 'ABANDONED'
AND customer_id = #{userId}
${orderby} ${pagination}

SELECT id, customer_id as "userId", subtotal, currency, discount_amount as "discountAmount", total, expires_at as "expiresAt", state_id as "stateId", flow_id as "flowId", created_time as "createdTime", last_modified_time as "lastModifiedTime" FROM cart WHERE state_id = 'EXPIRED'
AND customer_id = #{userId}
${orderby} ${pagination}

SELECT id, customer_id as "userId", session_id as "sessionId", subtotal, currency, coupon_codes as "couponCodes", discount_amount as "discountAmount", total, expires_at as "expiresAt", notes, state_id as "stateId", flow_id as "flowId", created_time as "createdTime", last_modified_time as "lastModifiedTime" FROM cart WHERE customer_id = #{userId}
AND state_id = #{stateId}
${orderby} ${pagination}

select count(*) from cart_item


        cart_id = #{cartId}


        AND product_id = #{productId}


        AND sku = #{sku}

SELECT id, cart_id as "cartId", product_id as "productId", variant_id as "variantId", sku, product_name as "productName", supplier_id as "supplierId", quantity, unit_price as "unitPrice", line_total as "lineTotal", created_time as "createdTime", last_modified_time as "lastModifiedTime", tenant FROM cart_item
cart_id = #{cartId}
AND product_id = #{productId}
AND sku = #{sku}
${orderby} ${pagination}

SELECT count(*) FROM cart c
LEFT JOIN cart_item ci ON ci.cart_id = c.id
WHERE c.id = #{cartId}

SELECT /* cart summary */ c.id as "cartId", c.customer_id as "userId", c.subtotal as "subtotal", c.currency as "currency", c.coupon_codes as "couponCodes", c.discount_amount as "discountAmount", c.total as "total", c.state_id as "stateId",
/* line item */ ci.id as "itemId", ci.variant_id as "variantId", ci.product_id as "productId", ci.sku as "sku", ci.quantity as "quantity", ci.unit_price as "unitPrice", ci.line_total as "lineTotal",
/* product display */ p.name as "productName", p.brand as "brand", p.slug as "productSlug", cat.name as "categoryName",
/* variant attributes (color, size) */ va_color.attribute_value as "variantColor", va_size.attribute_value as "variantSize",
/* primary image: prefer variant image, fallback to product image */ COALESCE(vma.cdn_url, vma.original_url, pma.cdn_url, pma.original_url) as "imageUrl",
/* stock status */ inv.available_quantity as "availableQuantity", inv.status as "stockStatus"
FROM cart c INNER JOIN cart_item ci ON ci.cart_id = c.id
/* product info */ LEFT JOIN products p ON p.id = ci.product_id LEFT JOIN categories cat ON cat.id = p.category_id
/* variant attributes — pivot color and size */ LEFT JOIN variant_attributes va_color ON va_color.variant_id = ci.variant_id AND va_color.attribute_key = 'color' LEFT JOIN variant_attributes va_size ON va_size.variant_id = ci.variant_id AND va_size.attribute_key = 'size'
/* variant primary image */ LEFT JOIN variant_media vm ON vm.variant_id = ci.variant_id AND vm.is_primary = true LEFT JOIN media_assets vma ON vma.id = vm.asset_id
/* product primary image (fallback if no variant image) */ LEFT JOIN product_media pm ON pm.product_id = ci.product_id AND pm.is_primary = true LEFT JOIN media_assets pma ON pma.id = pm.asset_id
/* inventory */ LEFT JOIN inventory_item inv ON inv.variant_id = ci.variant_id
WHERE c.customer_id = #{userId} AND c.state_id IN ('ACTIVE', 'CHECKOUT_INITIATED')
ORDER BY ci.created_time ASC ${pagination}

SELECT count(*) FROM cart c
INNER JOIN cart_item ci ON ci.cart_id = c.id
WHERE c.id = #{cartId}
